          t1r=_mm512_add_pd(x1_re,x3_re); t1i=_mm512_add_pd(x1_im,x3_im);
          t3r=_mm512_sub_pd(x1_re,x3_re); t3i=_mm512_sub_pd(x1_im,x3_im);
          x0_re=_mm512_add_pd(t0r,t1r); x0_im=_mm512_add_pd(t0i,t1i);
          x2_re=_mm512_sub_pd(t0r,t1r); x2_im=_mm512_sub_pd(t0i,t1i);
          x1_re=_mm512_add_pd(t2r,t3i); x1_im=_mm512_sub_pd(t2i,t3r);
